import networkx as nx

def maximum_flow(edge_list, _snode, _tnode, capacity="capacity", flow_func=None, **kwargs):
    G = nx.Graph()
    processed_edges = []
    for e in edge_list:
        if len(e) == 2:
            u, v = e
            processed_edges.append((u, v))
        elif len(e) >= 3:
            u, v, data = e[0], e[1], e[2]
            if isinstance(data, dict):
                # If only weight is provided, treat it as capacity
                if capacity not in data and "weight" in data and isinstance(data["weight"], (int, float)):
                    data = {**data, capacity: data["weight"]}
                processed_edges.append((u, v, data))
            else:
                # Numeric third element -> treat as capacity
                processed_edges.append((u, v, {capacity: data}))
        else:
            # Fallback (shouldn't occur with well-formed edge lists)
            continue

    G.add_edges_from(processed_edges)
    flow_value, flow_dict = nx.maximum_flow(G, _snode, _tnode, capacity=capacity, flow_func=flow_func, **kwargs)
    return flow_value```

