import networkx as nx

def clustering(edge_list, nodes=None, weight='weight'):
    G = nx.Graph()
    edges_to_add = []

    for e in edge_list:
        if len(e) == 2:
            u, v = e
            edges_to_add.append((u, v))
        elif len(e) == 3:
            u, v, data = e
            if isinstance(data, dict):
                edges_to_add.append((u, v, data))
            else:
                key = weight if isinstance(weight, str) else 'weight'
                edges_to_add.append((u, v, {key: data}))
        else:
            edges_to_add.append(e)

    G.add_edges_from(edges_to_add)
    result = nx.clustering(G, nodes=nodes, weight=weight)
    return result```

