import networkx as nx

def diameter(edge_list, config=None):
    G = nx.Graph()
    # Try to add as weighted edges if tuples of length 3; otherwise add as generic edges
    if edge_list:
        first = edge_list[0]
        if isinstance(first, (list, tuple)) and len(first) == 3 and not isinstance(first[2], dict):
            G.add_weighted_edges_from(edge_list)
        else:
            G.add_edges_from(edge_list)
    else:
        G.add_edges_from(edge_list)

    cfg = config or {}
    seed = cfg.get('seed', cfg.get('random_state', None))

    # Use the documented lower bound diameter function (2-sweep)
    result = nx.diameter(G, weight="weight")
    return result```

