import networkx as nx

def traveling_salesman_problem(edge_list, nodes=None, weight="weight", cycle=True, method=None, **kwargs):
    G = nx.Graph()
    # Add edges from edge_list; supports (u, v), (u, v, w), or (u, v, attr_dict)
    for e in edge_list:
        if len(e) == 2:
            u, v = e
            G.add_edge(u, v, **{weight: 1})
        elif len(e) == 3:
            u, v, w = e
            if isinstance(w, dict):
                data = dict(w)
                if weight != "weight" and "weight" in data and weight not in data:
                    data[weight] = data["weight"]
                G.add_edge(u, v, **data)
            else:
                G.add_edge(u, v, **{weight: w})
        else:
            raise ValueError("Each edge must be (u, v), (u, v, w), or (u, v, attr_dict)")
    result = nx.approximation.traveling_salesman_problem(
        G, nodes=nodes, weight=weight, cycle=cycle, method=method, **kwargs
    )
    return result
