import networkx as nx
from typing import Hashable, Iterable, Optional, Tuple


def best_cc_source_by_flow_clustering_undirected(
    edges: Iterable[Tuple[Hashable, Hashable, float]],
    t: Hashable,
    *,
    capacity_attr: str = "capacity",
) -> Hashable:
    G = nx.Graph()
    for u, v, w in edges:
        if w is None:
            return None
        if w < 0:
            raise ValueError(f"Negative capacity on edge ({u},{v}): {w}")
        G.add_edge(u, v, **{capacity_attr: float(w)})

    if t not in G:
        raise ValueError(f"Sink node t={t!r} is not present in the graph.")

    components = list(nx.connected_components(G))
    if not components:
        raise ValueError("Graph has no nodes.")

    clustering = nx.clustering(G)

    def pick_representative(C: set) -> Hashable:
        try:
            return min(C)
        except TypeError:
            return min(C, key=lambda x: str(x))

    best_s: Optional[Hashable] = None
    best_score: float = float("-inf")

    for C in components:
        s_c = pick_representative(C)

        if t not in C:
            flow_val = 0.0
        else:
            if not nx.has_path(G, s_c, t):
                flow_val = None
            else:
                flow_val, _ = nx.maximum_flow(G, s_c, t, capacity=capacity_attr)

        c_s = float(clustering.get(s_c, 0.0))
        score = float(flow_val) * (1.0 + c_s)

        if score > best_score:
            best_score = score
            best_s = s_c

    return best_s
